VALUES
  ('elementary-0489de64-moex-00161', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '2020年初爆發新冠肺炎疫情，各國被迫均採取嚴格的邊境管制，全球空運航班銳減，對於桃園機場 公司影響下列何者之描述錯誤？', '["飛機班機減少，影響機場規費、機場稅收入及特許權利金收入，然機場公司可以趁機整修各項硬體 設備", "機場工作人員若遭受感染，然航班及乘客相對減少，因此機場仍可正常運作不受影響", "機場公司需增派檢疫人力，使機場工作人員暴露於感染病風險之中", "取消班機過多，機場停機坪會呈現飽和甚至不足"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00162', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '依據國際民航組織的研究，實施最低垂直隔離（reducedverticalseparationminimum,RVSM），下列 之描述何者錯誤？', '["受強迫飛行高度將增加耗油", "減少飛航延誤", "新增6個空層", "管制員獲致更多的作業便利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00163', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '某電聯車，有4節車廂運轉，每車廂97人（座位24人，立位73人），最小班距為3分鐘（180秒）， 最大承載率為0.88。請計算最大路線運載容量：', '["7,760乘客人位/小時", "6,829乘客人位/小時", "3,880乘客人位/小時", "3,415乘客人位/小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00164', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '立法院112年4月三讀修正通過道路交通管理處罰條例部分條文，包括「提高未停讓行人罰責」、 「通盤檢討違規記點制度」、「提高無照駕駛罰則」、「加重危險駕駛罰則」四大核心，請問下列何 者之描述錯誤？', '["強化停讓保護行人：未停讓罰鍰上限由新臺幣3,600元提高至6,000元", "提高無照駕駛罰則：無照駕駛機車或小型車之罰鍰上限由新臺幣12,000元提高至24,000元", "通盤檢討違規記點制度：記點累計期間由半年延長至1年，於1年內記點每達12點，吊扣駕駛執 照2個月", "加重危險駕駛罰則：提高罰鍰上限由新臺幣24,000元提高至48,000元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00165', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '運輸為經濟活動的一環，運輸服務可視為有價商品（服務），請問下列廠商（生產者）在運輸定價理 論之描述何者錯誤？', '["價格歧視與差別定價：以對於所提供的不相同服務（或產品），依不同的使用組群，訂定不同價格 為定價原則", "最大獲利定價：獲利最大為定價原則", "效率定價：以達成社會資源最有效使用為定價原則", "邊際成本定價：考慮應有的超額利潤後，再以其邊際成本為定價原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00166', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '自從全球疫情大爆發後，為減少員工及通勤接觸，實施通訊會議及在家上班，以社會角度而言，有關 在家上班之敘述，下列何者錯誤？', '["維持運輸系統原設計容量及服務水準的時間延後", "間接降低交通擁擠及空氣污染，維持生活品質", "節省了雇主及員工辦公空間、減少水電空調等能源消耗", "取代部分工作通勤旅次"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00167', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '由於運輸服務具有公共性且影響經濟成長與國民生活，各國皆實施運輸實施管制，下列對運輸產業 在經濟管制之描述何者錯誤？', '["對運輸業者經營路線與排班的管制", "對運輸業者進入或退出市場的管制", "對運輸業者定價費率的管制", "對運輸業者實施確保安全的管制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00168', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '自從嚴重特殊傳染性肺炎（COVID-19）疫情爆發通訊會議盛行後，請問下列通訊與運輸的潛在互動 關係何者錯誤？', '["替代關係：通訊會取代部分的運輸旅次", "增強關係：通訊的發展會增加對運輸系統的使用", "互補關係：通訊與運輸系統共同存在增強彼此的使用效率", "獨立關係：通訊與運輸系統各自發展沒有相互影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00169', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '依據鐵路法第2條，鐵路指：', '["以導引之運輸系統及其有關設施", "以軌道導引之運輸系統及其有關設施", "以軌道導引動力車輛行駛之運輸系統及其有關設施", "以軌道導引動力車輛行駛於專有路權上之運輸系統及其有關設施"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00170', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '依據民用航空法第2條，下列名詞解釋那一項錯誤？', '["民用航空運輸業：指以航空器直接載運客、貨、郵件，取得報酬之事業", "普通航空業：指以航空器經營民用航空運輸業以外之飛航業務而受報酬之事業，包括空中遊覽、勘 察、照測、消防、搜尋、救護、拖吊、噴灑、拖靶勤務、商務專機及其他經核准之飛航業務", "航空貨運承攬業：指以自己之名義，為他人之計算，使民用航空運輸業運送航空貨物及非具有通信 性質之國際貿易商業文件而受報酬之事業", "航空站地勤業：指提供空運進口、出口、轉運或轉口貨物集散與進出航空站管制區所需之通關、倉 儲場所、設備及服務而受報酬之事業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
